const [activePath, setActivePath] = useState(0)
const [progress, setProgress] = useState(0)
const [statsCounted, setStatsCounted] = useState(false)
const [animatedStats, setAnimatedStats] = useState<number[]>([0, 0, 0, 0])
const statsSectionRef = useRef<HTMLDivElement>(null)
const path = PATHS[activePath]
const PathIcon = path.icon

// Count-up animation via IntersectionObserver
useEffect(() => {
  const el = statsSectionRef.current
  if (!el) return
  const observer = new IntersectionObserver(
    (entries) => {
      if (entries[0].isIntersecting && !statsCounted) {
        setStatsCounted(true)
      }
    },
    { threshold: 0.3 }
  )
  observer.observe(el)
  return () => observer.disconnect()
}, [statsCounted])

// Animate count-up when stats section becomes visible
useEffect(() => {
  if (!statsCounted) return
  const targets = [2400, 890, 18, 4.9]
  const durations = [1600, 1400, 1200, 1200]
  const decimals = [0, 0, 0, 1]
  let frameId: number

  targets.forEach((target, i) => {
    const startTime = performance.now()
    const duration = durations[i]
    const dec = decimals[i]

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime
      const progress = Math.min(elapsed / duration, 1)
      // Ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      const current = eased * target
      setAnimatedStats(prev => {
        const next = [...prev]
        next[i] = dec > 0 ? parseFloat(current.toFixed(dec)) : Math.round(current)
        return next
      })
      if (progress < 1) {
        frameId = requestAnimationFrame(animate)
      }
    }
    // Stagger each stat by 150ms
    setTimeout(() => {
      frameId = requestAnimationFrame(animate)
    }, i * 150)
  })

  return () => {
    if (frameId) cancelAnimationFrame(frameId)
  }
}, [statsCounted])

